// Carry the filename forward alongside the binary PDF data
const filename = $('Prepare compilation ready').first().json.filename || "Resume.pdf";
const candidateName = $('Prepare compilation ready').first().json.candidateName || "Candidate";

// Pass binary through untouched, just add metadata
const item = $input.first();

return [{
  json: {
    filename,
    candidateName
  },
  binary: {
    pdfData: item.binary.pdfData
  }
}];

const raw = $input.first().json.output || "";

// Pull candidate name from Resume extractor for filename
let candidateName = "Candidate";
try {
  const resumeOutput = $('Resume extractor').first().json.output || "";
  const nameMatch = resumeOutput.match(/"full_name"\s*:\s*"([^"]+)"/);
  if (nameMatch) candidateName = nameMatch[1];
} catch(e) {}

// Sanitize name for filename (remove special chars)
const safeFilename = candidateName.replace(/[^a-zA-Z0-9\s]/g, "").trim().replace(/\s+/g, "_") + "_Resume.pdf";

// 1. Strip markdown fences
let latex = raw
  .replace(/^```latex\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/```\s*$/i, "")
  .trim();

// 2. Strip anything before \documentclass
const docStart = latex.indexOf("\\documentclass");
if (docStart > 0) {
  latex = latex.slice(docStart);
}

// 3. Strip anything after \end{document}
const docEnd = latex.lastIndexOf("\\end{document}");
if (docEnd !== -1) {
  latex = latex.slice(0, docEnd + "\\end{document}".length);
}

// 4. Build request body
const requestBody = JSON.stringify({
  compiler: "pdflatex",
  resources: [{ main: true, content: latex }]
});

return [{ 
  json: { 
    requestBody,
    filename: safeFilename,
    candidateName,
    latexPreview: latex.slice(0, 200)
  } 
}];

// ── Parse ATS Score ──────────────────────────────────────
let atsScore = 0;
let atsRecommendation = "N/A";
let atsGaps = [];
let atsKeywords = [];

try {
  const atsRaw = $('ATS Score Agent').first().json.output || "";
  const atsClean = atsRaw
    .replace(/```json/gi, "")
    .replace(/```/g, "")
    .trim();
  const firstBrace = atsClean.indexOf("{");
  const lastBrace = atsClean.lastIndexOf("}");
  const atsJson = JSON.parse(atsClean.slice(firstBrace, lastBrace + 1));
  atsScore = atsJson.score || 0;
  atsRecommendation = atsJson.recommendation || "N/A";
  atsGaps = atsJson.gaps || [];
  atsKeywords = atsJson.top_matching_keywords || [];
} catch(e) {
  atsGaps = ["Could not parse ATS analysis"];
}

// ── Score emoji bar ───────────────────────────────────────
function scoreBar(score) {
  const filled = Math.round(score / 10);
  return "🟩".repeat(filled) + "⬜".repeat(10 - filled);
}

function recommendationEmoji(rec) {
  if (rec.includes("Strong")) return "🚀";
  if (rec.includes("Good")) return "✅";
  if (rec.includes("Moderate")) return "⚠️";
  return "🔴";
}

// ── Build Telegram caption ────────────────────────────────
const candidateName = $('Compile & convert to pdf file').first().json.candidateName || "Candidate";
const filename = $('Compile & convert to pdf file').first().json.filename || "Resume.pdf";

const gapLines = atsGaps.map((g, i) => `   ${i + 1}. ${g}`).join("\n");

const caption = `${recommendationEmoji(atsRecommendation)} *${candidateName}* — Resume Ready

📊 *ATS Match Score: ${atsScore}/100*
${scoreBar(atsScore)} ${atsRecommendation}

🔍 *Top Gaps to Address:*
${gapLines}

📄 File: ${filename}
🤖 ATS-optimized & JD-matched`;

// ── Clean Cover Letter HTML ───────────────────────────────
let coverLetterHtml = "";
try {
  const clRaw = $('Cover Letter Agent').first().json.output || "";
  coverLetterHtml = clRaw
    .replace(/^```html\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```\s*$/i, "")
    .trim();
  // Ensure it starts at <!DOCTYPE
  const dtIdx = coverLetterHtml.indexOf("<!DOCTYPE");
  const htmlIdx = coverLetterHtml.indexOf("<html");
  const startIdx = dtIdx !== -1 ? dtIdx : (htmlIdx !== -1 ? htmlIdx : 0);
  if (startIdx > 0) coverLetterHtml = coverLetterHtml.slice(startIdx);
} catch(e) {
  coverLetterHtml = "<html><body><p>Cover letter generation failed.</p></body></html>";
}

// ── Convert HTML to binary for Telegram ──────────────────
const htmlBytes = Buffer.from(coverLetterHtml, "utf-8");
const htmlBase64 = htmlBytes.toString("base64");

// Pass through the PDF binary too
const pdfBinary = $('Compile & convert to pdf file').first().binary?.pdfData;

return [{
  json: {
    caption,
    filename,
    candidateName,
    atsScore,
    atsRecommendation,
    coverLetterFilename: candidateName.replace(/[^a-zA-Z0-9\s]/g,"").trim().replace(/\s+/g,"_") + "_CoverLetter.html",
    coverLetterHtml,
    htmlBase64
  },
  binary: {
    pdfData: pdfBinary,
    coverLetterFile: {
      data: htmlBase64,
      mimeType: "text/html",
      fileName: candidateName.replace(/[^a-zA-Z0-9\s]/g,"").trim().replace(/\s+/g,"_") + "_CoverLetter.html",
      fileExtension: "html"
    }
  }
}];
